import sqlite3InitModule from '@sqlite.org/sqlite-wasm';

let sqlite3 = null;
let opfsPoolPromise = null;
const databases = new Map();
const statements = new Map();
let nextDatabaseId = 1;
let nextStatementId = 1;

function respond(id, data) {
  postMessage({ id, data });
}

function fail(id, error) {
  postMessage({ id, error: error instanceof Error ? error.message : String(error) });
}

function getOpfsPool() {
  if (!opfsPoolPromise) {
    opfsPoolPromise = sqlite3.installOpfsSAHPoolVfs({
      name: 'moneym-opfs-sahpool',
      directory: '.moneym-opfs-sahpool',
      initialCapacity: 32,
      clearOnInit: false,
    });
  }
  return opfsPoolPromise;
}

function poolPath(fileName) {
  return fileName.startsWith('/') ? fileName : `/${fileName}`;
}

function bytesToBase64(bytes) {
  let binary = '';
  const chunkSize = 0x8000;
  for (let offset = 0; offset < bytes.length; offset += chunkSize) {
    binary += String.fromCharCode(...bytes.subarray(offset, offset + chunkSize));
  }
  return btoa(binary);
}

function base64ToBytes(value) {
  const binary = atob(value);
  const bytes = new Uint8Array(binary.length);
  for (let index = 0; index < binary.length; index++) bytes[index] = binary.charCodeAt(index);
  return bytes;
}

function respondToPort(request, data) {
  request.responsePort.postMessage({ data });
  request.responsePort.close();
}

function failToPort(request, error) {
  request.responsePort.postMessage({ error: error instanceof Error ? error.message : String(error) });
  request.responsePort.close();
}

async function openRequest(id, request) {
  try {
    const opfsPool = await getOpfsPool();
    const databaseId = nextDatabaseId++;
    databases.set(databaseId, new opfsPool.OpfsSAHPoolDb(request.fileName));
    respond(id, { databaseId });
  } catch (error) {
    fail(id, error);
  }
}

async function exportRequest(_id, request) {
  try {
    const opfsPool = await getOpfsPool();
    const path = poolPath(request.fileName);
    const value = opfsPool.getFileNames().includes(path)
      ? bytesToBase64(opfsPool.exportFile(path))
      : null;
    respondToPort(request, { value });
  } catch (error) {
    failToPort(request, error);
  }
}

async function importRequest(_id, request) {
  try {
    const opfsPool = await getOpfsPool();
    opfsPool.importDb(poolPath(request.fileName), base64ToBytes(request.value));
    respondToPort(request, { value: 'true' });
  } catch (error) {
    failToPort(request, error);
  }
}

async function unlinkRequest(_id, request) {
  try {
    const opfsPool = await getOpfsPool();
    respondToPort(request, { value: String(opfsPool.unlink(poolPath(request.fileName))) });
  } catch (error) {
    failToPort(request, error);
  }
}

function prepareRequest(id, request) {
  try {
    const database = databases.get(request.databaseId);
    if (!database) throw new Error(`Invalid database ID: ${request.databaseId}`);
    const statement = database.prepare(request.sql);
    const statementId = nextStatementId++;
    statements.set(statementId, statement);
    const columnNames = [];
    for (let index = 0; index < statement.columnCount; index++) {
      columnNames.push(sqlite3.capi.sqlite3_column_name(statement, index));
    }
    respond(id, {
      statementId,
      parameterCount: sqlite3.capi.sqlite3_bind_parameter_count(statement),
      columnNames,
    });
  } catch (error) {
    fail(id, error);
  }
}

function stepRequest(id, request) {
  try {
    const statement = statements.get(request.statementId);
    if (!statement) throw new Error(`Invalid statement ID: ${request.statementId}`);
    statement.reset();
    statement.clearBindings();
    request.bindings.forEach((value, index) => statement.bind(index + 1, value));
    const rows = [];
    const columnTypes = [];
    while (statement.step()) {
      if (columnTypes.length === 0) {
        for (let index = 0; index < statement.columnCount; index++) {
          columnTypes.push(sqlite3.capi.sqlite3_column_type(statement, index));
        }
      }
      rows.push(statement.get([]));
    }
    respond(id, { rows, columnTypes });
  } catch (error) {
    fail(id, error);
  }
}

function closeRequest(id, request) {
  try {
    if (request.statementId != null) {
      const statement = statements.get(request.statementId);
      if (!statement) throw new Error(`Invalid statement ID: ${request.statementId}`);
      statement.finalize();
      statements.delete(request.statementId);
    }
    if (request.databaseId != null) {
      const database = databases.get(request.databaseId);
      if (!database) throw new Error(`Invalid database ID: ${request.databaseId}`);
      database.close();
      databases.delete(request.databaseId);
    }
  } catch (error) {
    fail(id, error);
  }
}

const commands = {
  open: openRequest,
  prepare: prepareRequest,
  step: stepRequest,
  close: closeRequest,
  'moneym-export': exportRequest,
  'moneym-import': importRequest,
  'moneym-unlink': unlinkRequest,
};
const queue = [];

function handleMessage(event) {
  const request = event.data;
  const command = request?.data?.cmd;
  if (!command || !commands[command]) {
    fail(request?.id, `Invalid request command: ${command}`);
    return;
  }
  commands[command](request.id, request.data);
}

onmessage = event => sqlite3 ? handleMessage(event) : queue.push(event);

sqlite3InitModule().then(instance => {
  sqlite3 = instance;
  while (queue.length > 0) handleMessage(queue.shift());
}).catch(error => {
  while (queue.length > 0) {
    const request = queue.shift()?.data;
    fail(request?.id, error);
  }
});
